Here are the public test cases for feature5_3_publish_aot:
{
  "description": "Decide whether ahead-of-time (AOT) publishing is requested. An optional build-parameter string is consulted first: if it contains the publish-AOT flag set to true or false (case-insensitive, whitespace ignored) that value wins. Otherwise the project manifest's publish-AOT property is read; if it is absent or not a boolean the result defaults to false.",
  "cases": [
    {
      "input": {
        "project_file": "<Project Sdk=\"Microsoft.NET.Sdk\">\n  <PropertyGroup>\n    <TargetFramework>netcoreapp3.1</TargetFramework>\n    <OutputType>Library</OutputType>\n  </PropertyGroup>\n</Project>\n",
        "msbuild_parameters": null
      },
      "expected_output": "publish_aot=false\n"
    },
    {
      "input": {
        "project_file": "<Project Sdk=\"Microsoft.NET.Sdk\">\n  <PropertyGroup>\n    <TargetFramework>netcoreapp3.1</TargetFramework>\n    <OutputType>Library</OutputType>\n  </PropertyGroup>\n</Project>\n",
        "msbuild_parameters": "publishaot=true"
      },
      "expected_output": "publish_aot=true\n"
    },
    {
      "input": {
        "project_file": "<Project Sdk=\"Microsoft.NET.Sdk\">\n  <PropertyGroup>\n    <OutputType>Exe</OutputType>\n    <TargetFramework>net7.0</TargetFramework>\n    <PublishAot>true</PublishAot>\n  </PropertyGroup>\n</Project>\n",
        "msbuild_parameters": null
      },
      "expected_output": "publish_aot=true\n"
    },
    {
      "input": {
        "project_file": "<Project Sdk=\"Microsoft.NET.Sdk\">\n  <PropertyGroup>\n    <OutputType>Exe</OutputType>\n    <TargetFramework>net7.0</TargetFramework>\n    <PublishAot>true</PublishAot>\n  </PropertyGroup>\n</Project>\n",
        "msbuild_parameters": "publishAOT=False"
      },
      "expected_output": "publish_aot=false\n"
    }
  ]
}

